python3 -c "
import csv, json
active = []
with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        if row['is_resolved'] == 'False':
            active.append(row)

# Print questions with their current predictions that need reviewing
for q in sorted(active, key=lambda x: x['resolution_date']):
    pred = q['my_prediction']
    if pred != 'None':
        try:
            p = json.loads(pred.replace(\"'\", '\"'))
        except:
            p = {}
        top = max(p.items(), key=lambda x: x[1]) if p else ('', 0)
        print(f\"{q['qid']}|{q['resolution_date']}|{top[0][:30]}:{top[1]}|{q['title'][:65]}\")
    else:
        print(f\"{q['qid']}|{q['resolution_date']}|NO PRED|{q['title'][:65]}\")
"
